// Generate Notion API URLs for all guideline pages
var pageIds = [
  '7bd2cbe0fce0449198ecb23ff4a2f76f',
  '9959894476734da3b402c90b124b1f77',
  '2aa5b6e0c94f8058b0aefddd02655887',
  'b4c008b47eb74846b48c37c652ec2650'
];

return pageIds.map(function(id) {
  return { json: { url: 'https://notion-api.splitbee.io/v1/page/' + id, pageId: id } };
});

// Parse Notion API response into readable guidelines text
function extractBlockText(block) {
  if (!block || !block.value || !block.value.properties || !block.value.properties.title) return '';
  var titleArr = block.value.properties.title;
  var text = '';
  for (var i = 0; i < titleArr.length; i++) {
    if (typeof titleArr[i][0] === 'string') {
      text = text + titleArr[i][0];
    }
  }
  return text.trim();
}

function formatBlock(block) {
  var text = extractBlockText(block);
  if (!text || text === '\u2023') return '';
  var type = (block && block.value && block.value.type) ? block.value.type : '';
  if (type === 'header') return '\n# ' + text;
  if (type === 'sub_header') return '\n## ' + text;
  if (type === 'sub_sub_header') return '\n### ' + text;
  if (type === 'bulleted_list') return '- ' + text;
  if (type === 'numbered_list') return '1. ' + text;
  if (type === 'callout') return '> ' + text;
  if (type === 'toggle') return '> ' + text;
  if (type === 'page') return '\n--- PAGE: ' + text + ' ---';
  return text;
}

var guidelines = '';
var items = $input.all();
for (var idx = 0; idx < items.length; idx++) {
  var itemData = items[idx].json;
  if (!itemData) continue;
  // Handle aggregated data (array of page results)
  var pages = Array.isArray(itemData.data) ? itemData.data : [itemData];
  for (var p = 0; p < pages.length; p++) {
    var pageData = pages[p];
    if (!pageData || typeof pageData !== 'object') continue;
    var keys = Object.keys(pageData);
    for (var k = 0; k < keys.length; k++) {
      var block = pageData[keys[k]];
      if (!block || !block.value) continue;
      var formatted = formatBlock(block);
      if (formatted) {
        guidelines = guidelines + formatted + '\n';
      }
    }
  }
}

// Fallback if scraping failed
if (!guidelines || guidelines.length < 100) {
  guidelines = 'SCRAPING FAILED - Please check Notion API availability';
}

return {
  json: {
    guidelines: guidelines,
    guidelinesLength: guidelines.length,
    scrapedFromNotion: guidelines.length > 200,
    source: guidelines.length > 200 ? 'Notion API (Live)' : 'Scraping Failed'
  }
};

// Convert criteria text and workflow JSON to binary for Gemini Files API upload
var criteria = $input.first().json.response || $input.first().json.text || 'No criteria';
var formData = $('Submit workflow for review').first().json;
var workflowRaw = formData['Workflow JSON File'] || '{}';
var workflowJson = (typeof workflowRaw === 'object') ? JSON.stringify(workflowRaw, null, 2) : workflowRaw;

// Output 2 items: criteria file + workflow file
return [
  {
    json: { fileType: 'criteria' },
    binary: {
      data: await this.helpers.prepareBinaryData(
        Buffer.from(criteria, 'utf-8'),
        'criteria.txt',
        'text/plain'
      )
    }
  },
  {
    json: { fileType: 'workflow' },
    binary: {
      data: await this.helpers.prepareBinaryData(
        Buffer.from(workflowJson, 'utf-8'),
        'workflow.json',
        'application/json'
      )
    }
  }
];

